Below is a complete, thread-safe, generic LRU cache with TTL-based expiry, an eviction callback, and metrics (hits, misses, evictions) plus a Stats() method. It avoids calling user callbacks while holding the internal lock to prevent deadlocks, and uses atomics for metrics to reduce contention.

Save as package lru.

```go
package lru

import (
	"container/list"
	"sync"
	"sync/atomic"
	"time"
)

type entry[K comparable, V any] struct {
	key       K
	value     V
	expiresAt time.Time
}

type Options[K comparable, V any] struct {
	Capacity int           // number of items cache can hold; if <=0 defaults to 1024
	TTL      time.Duration // 0 means items don't expire
	OnEvict  func(key K, value V)
}

type Stats struct {
	Hits      int64
	Misses    int64
	Evictions int64
	Size      int
	Capacity  int
}

type Cache[K comparable, V any] struct {
	mu       sync.Mutex
	capacity int
	ttl      time.Duration
	onEvict  func(K, V)

	items map[K]*list.Element
	order *list.List

	// metric counters
	hits      int64
	misses    int64
	evictions int64

	// cleanup goroutine control
	stopCh   chan struct{}
	stopOnce sync.Once
}

// New creates a new LRU cache with the provided options.
// If opts.Capacity <= 0, it defaults to 1024.
func New[K comparable, V any](opts Options[K, V]) *Cache[K, V] {
	if opts.Capacity <= 0 {
		opts.Capacity = 1024
	}
	c := &Cache[K, V]{
		capacity: opts.Capacity,
		ttl:      opts.TTL,
		onEvict:  opts.OnEvict,
		items:    make(map[K]*list.Element, opts.Capacity),
		order:    list.New(),
		stopCh:   make(chan struct{}),
	}

	if opts.TTL > 0 {
		go c.startCleanup()
	}

	return c
}

// Get returns the value for the key and true if present and not expired.
// It updates the LRU ordering on a hit.
func (c *Cache[K, V]) Get(key K) (V, bool) {
	var zero V

	c.mu.Lock()
	elem, ok := c.items[key]
	if !ok {
		atomic.AddInt64(&c.misses, 1)
		c.mu.Unlock()
		return zero, false
	}

	e := elem.Value.(*entry[K, V])
	// Check expiry
	if !e.expiresAt.IsZero() && time.Now().After(e.expiresAt) {
		// Remove expired element (collect to call evict callback after unlocking)
		k := e.key
		v := e.value
		c.removeElementLocked(elem)
		atomic.AddInt64(&c.misses, 1)
		atomic.AddInt64(&c.evictions, 1)
		onEv := c.onEvict
		c.mu.Unlock()

		if onEv != nil {
			onEv(k, v)
		}
		return zero, false
	}

	// Hit
	c.order.MoveToFront(elem)
	atomic.AddInt64(&c.hits, 1)
	val := e.value
	c.mu.Unlock()
	return val, true
}

// Put inserts or updates the value for the key. If insertion would
// exceed capacity the least-recently-used item is evicted.
func (c *Cache[K, V]) Put(key K, value V) {
	var evicted []entry[K, V]

	c.mu.Lock()
	if elem, ok := c.items[key]; ok {
		e := elem.Value.(*entry[K, V])
		e.value = value
		if c.ttl > 0 {
			e.expiresAt = time.Now().Add(c.ttl)
		} else {
			e.expiresAt = time.Time{}
		}
		c.order.MoveToFront(elem)
		c.mu.Unlock()
		return
	}

	// Evict if needed
	if c.order.Len() >= c.capacity {
		oldest := c.order.Back()
		if oldest != nil {
			e := oldest.Value.(*entry[K, V])
			evicted = append(evicted, *e)
			c.removeElementLocked(oldest)
			atomic.AddInt64(&c.evictions, 1)
		}
	}

	ent := &entry[K, V]{
		key:   key,
		value: value,
	}
	if c.ttl > 0 {
		ent.expiresAt = time.Now().Add(c.ttl)
	}
	elem := c.order.PushFront(ent)
	c.items[key] = elem
	c.mu.Unlock()

	// Call eviction callback(s) without holding lock
	if c.onEvict != nil && len(evicted) > 0 {
		for _, ev := range evicted {
			c.onEvict(ev.key, ev.value)
		}
	}
}

// Len returns the current number of items in the cache.
func (c *Cache[K, V]) Len() int {
	c.mu.Lock()
	n := c.order.Len()
	c.mu.Unlock()
	return n
}

// Stats returns a snapshot of cache statistics.
func (c *Cache[K, V]) Stats() Stats {
	s := Stats{
		Hits:      atomic.LoadInt64(&c.hits),
		Misses:    atomic.LoadInt64(&c.misses),
		Evictions: atomic.LoadInt64(&c.evictions),
	}
	c.mu.Lock()
	s.Size = c.order.Len()
	s.Capacity = c.capacity
	c.mu.Unlock()
	return s
}

// Close stops the background cleanup goroutine (if any).
func (c *Cache[K, V]) Close() {
	c.stopOnce.Do(func() {
		close(c.stopCh)
	})
}

// startCleanup runs a goroutine that periodically scans for expired entries.
func (c *Cache[K, V]) startCleanup() {
	interval := c.ttl / 2
	if interval <= 0 {
		interval = time.Millisecond
	}
	ticker := time.NewTicker(interval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			c.cleanupExpired()
		case <-c.stopCh:
			return
		}
	}
}

// cleanupExpired scans from the back and removes expired entries.
// Eviction callbacks are invoked outside the lock.
func (c *Cache[K, V]) cleanupExpired() {
	now := time.Now()
	var evicted []entry[K, V]

	c.mu.Lock()
	for e := c.order.Back(); e != nil; {
		prev := e.Prev()
		en := e.Value.(*entry[K, V])
		if !en.expiresAt.IsZero() && now.After(en.expiresAt) {
			evicted = append(evicted, *en)
			c.removeElementLocked(e)
			atomic.AddInt64(&c.evictions, 1)
		}
		e = prev
	}
	c.mu.Unlock()

	if c.onEvict != nil && len(evicted) > 0 {
		for _, ev := range evicted {
			c.onEvict(ev.key, ev.value)
		}
	}
}

// removeElementLocked removes the element from the lists and map.
// Caller must hold c.mu.
// Note: does not invoke callback or update evictions counter.
func (c *Cache[K, V]) removeElementLocked(elem *list.Element) {
	if elem == nil {
		return
	}
	en := elem.Value.(*entry[K, V])
	delete(c.items, en.key)
	c.order.Remove(elem)
}
```

Notes:
- TTL is global for the cache (per-entry TTL is set at insertion using the cache TTL).
- Eviction callbacks are executed without holding the internal lock to avoid deadlocks; eviction count is still incremented while holding the lock where removal happens.
- Metrics (hits, misses, evictions) use atomic counters for low-contention reads via Stats().
